                </div>
                <div class="xana-audit-page-body">
                    ${sortedGroups.map(([code, items]) => `
                        <section class="xana-audit-group">
                            <h3 class="xana-audit-group-title">
                                ${escapeHtml(formatViolationCode(code))}
                                <span class="xana-audit-count">${items.length}</span>
